export function aStarGridShortestPath(
	grid: number[][],
	start: readonly [number, number],
	end: readonly [number, number]
): number | null {
	const rows = grid.length;
	if (rows === 0) return null;
	const cols = grid[0]?.length ?? 0;
	if (cols === 0) return null;

	const [sr, sc] = start;
	const [er, ec] = end;

	const inBounds = (r: number, c: number) => r >= 0 && r < rows && c >= 0 && c < cols;

	if (!inBounds(sr, sc) || !inBounds(er, ec)) return null;
	if (grid[sr][sc] !== 0 || grid[er][ec] !== 0) return null;
	if (sr === er && sc === ec) return 0;

	const manhattan = (r: number, c: number) => Math.abs(r - er) + Math.abs(c - ec);

	type Node = { r: number; c: number; g: number; f: number };

	class MinHeap {
		private data: Node[] = [];

		get size(): number {
			return this.data.length;
		}

		push(item: Node): void {
			this.data.push(item);
			this.bubbleUp(this.data.length - 1);
		}

		pop(): Node | undefined {
			if (this.data.length === 0) return undefined;
			const top = this.data[0];
			const last = this.data.pop()!;
			if (this.data.length > 0) {
				this.data[0] = last;
				this.bubbleDown(0);
			}
			return top;
		}

		private bubbleUp(index: number): void {
			while (index > 0) {
				const parent = (index - 1) >> 1;
				if (this.compare(this.data[index], this.data[parent]) >= 0) break;
				[this.data[index], this.data[parent]] = [this.data[parent], this.data[index]];
				index = parent;
			}
		}

		private bubbleDown(index: number): void {
			const n = this.data.length;
			for (;;) {
				let smallest = index;
				const left = index * 2 + 1;
				const right = index * 2 + 2;

				if (left < n && this.compare(this.data[left], this.data[smallest]) < 0) smallest = left;
				if (right < n && this.compare(this.data[right], this.data[smallest]) < 0) smallest = right;

				if (smallest === index) break;
				[this.data[index], this.data[smallest]] = [this.data[smallest], this.data[index]];
				index = smallest;
			}
		}

		private compare(a: Node, b: Node): number {
			if (a.f !== b.f) return a.f - b.f;
			return a.g - b.g;
		}
	}

	const gScore: number[][] = Array.from({ length: rows }, () => Array(cols).fill(Infinity));
	gScore[sr][sc] = 0;

	const open = new MinHeap();
	open.push({ r: sr, c: sc, g: 0, f: manhattan(sr, sc) });

	const dirs = [
		[1, 0],
		[-1, 0],
		[0, 1],
		[0, -1],
	] as const;

	while (open.size > 0) {
		const current = open.pop()!;
		const { r, c, g } = current;

		if (g !== gScore[r][c]) continue;

		if (r === er && c === ec) return g;

		for (const [dr, dc] of dirs) {
			const nr = r + dr;
			const nc = c + dc;

			if (!inBounds(nr, nc)) continue;
			if (grid[nr][nc] !== 0) continue;

			const ng = g + 1;
			if (ng < gScore[nr][nc]) {
				gScore[nr][nc] = ng;
				open.push({ r: nr, c: nc, g: ng, f: ng + manhattan(nr, nc) });
			}
		}
	}

	return null;
}

export function binarySearchBoundary(values: number[], target: number): number {
	let left = 0;
	let right = values.length - 1;
	let result = -1;

	while (left <= right) {
		const mid = left + Math.floor((right - left) / 2);

		if (values[mid] === target) {
			result = mid;
			right = mid - 1;
		} else if (values[mid] < target) {
			left = mid + 1;
		} else {
			right = mid - 1;
		}
	}

	return result;
}

export function binarySearchFirstLastPosition(values: number[], target: number): [number, number] {
	const findBound = (isFirst: boolean): number => {
		let left = 0;
		let right = values.length - 1;
		let bound = -1;

		while (left <= right) {
			const mid = left + Math.floor((right - left) / 2);

			if (values[mid] === target) {
				bound = mid;
				if (isFirst) {
					right = mid - 1;
				} else {
					left = mid + 1;
				}
			} else if (values[mid] < target) {
				left = mid + 1;
			} else {
				right = mid - 1;
			}
		}

		return bound;
	};

	const first = findBound(true);
	if (first === -1) return [-1, -1];

	const last = findBound(false);
	return [first, last];
}

export function evaluateBooleanExpression(expression: string): boolean {
	let i = 0;

	const skipWhitespace = () => {
		while (i < expression.length && /\s/.test(expression[i])) i++;
	};

	const parseExpression = (): boolean => parseOr();

	const parseOr = (): boolean => {
		let left = parseAnd();
		while (true) {
			skipWhitespace();
			if (expression.slice(i, i + 2) === '||') {
				i += 2;
				const right = parseAnd();
				left = left || right;
			} else {
				break;
			}
		}
		return left;
	};

	const parseAnd = (): boolean => {
		let left = parseUnary();
		while (true) {
			skipWhitespace();
			if (expression.slice(i, i + 2) === '&&') {
				i += 2;
				const right = parseUnary();
				left = left && right;
			} else {
				break;
			}
		}
		return left;
	};

	const parseUnary = (): boolean => {
		skipWhitespace();
		if (expression[i] === '!') {
			i++;
			return !parseUnary();
		}
		return parsePrimary();
	};

	const parsePrimary = (): boolean => {
		skipWhitespace();

		if (expression[i] === '(') {
			i++;
			const value = parseExpression();
			skipWhitespace();
			if (expression[i] !== ')') {
				throw new Error('Expected closing parenthesis');
			}
			i++;
			return value;
		}

		if (expression.slice(i, i + 4) === 'true') {
			i += 4;
			return true;
		}

		if (expression.slice(i, i + 5) === 'false') {
			i += 5;
			return false;
		}

		throw new Error(`Unexpected token at position ${i}`);
	};

	const result = parseExpression();
	skipWhitespace();

	if (i !== expression.length) {
		throw new Error(`Unexpected trailing input at position ${i}`);
	}

	return result;
}

import * as fs from 'fs';
import * as path from 'path';

function collectTsFiles(dir: string, out: string[]): void {
	const entries = fs.readdirSync(dir, { withFileTypes: true });
	for (const entry of entries) {
		const fullPath = path.join(dir, entry.name);
		if (entry.isDirectory()) {
			collectTsFiles(fullPath, out);
		} else if (
			entry.isFile() &&
			entry.name.endsWith('.ts') &&
			!entry.name.endsWith('.d.ts')
		) {
			out.push(path.resolve(fullPath));
		}
	}
}

function normalizePath(p: string): string {
	return path.normalize(path.resolve(p));
}

function tryResolveLocalImport(fromFile: string, specifier: string): string | null {
	const base = path.resolve(path.dirname(fromFile), specifier);
	const candidates = [
		base,
		`${base}.ts`,
		path.join(base, 'index.ts'),
	];

	for (const candidate of candidates) {
		if (fs.existsSync(candidate) && fs.statSync(candidate).isFile()) {
			if (candidate.endsWith('.ts') && !candidate.endsWith('.d.ts')) {
				return normalizePath(candidate);
			}
		}
	}
	return null;
}

function parseLocalImports(filePath: string): string[] {
	const content = fs.readFileSync(filePath, 'utf8');
	const imports: string[] = [];
	const patterns: RegExp[] = [
		/import\s+[^'"]*from\s+['"]([^'"]+)['"]/g,
		/import\s+['"]([^'"]+)['"]/g,
		/export\s+[^'"]*from\s+['"]([^'"]+)['"]/g,
		/import\s*\(\s*['"]([^'"]+)['"]\s*\)/g,
	];

	for (const re of patterns) {
		let match: RegExpExecArray | null;
		while ((match = re.exec(content)) !== null) {
			const spec = match[1];
			if (spec.startsWith('./') || spec.startsWith('../')) {
				imports.push(spec);
			}
		}
	}

	return imports;
}

function canonicalCycle(cycle: string[]): string {
	const core = cycle.slice(0, -1);
	if (core.length === 0) return '';
	let minIdx = 0;
	for (let i = 1; i < core.length; i++) {
		if (core[i] < core[minIdx]) minIdx = i;
	}
	const rotated = core.slice(minIdx).concat(core.slice(0, minIdx));
	return rotated.join('->');
}

export function detectCycles(rootDir: string): string[][] {
	const root = normalizePath(rootDir);
	const files: string[] = [];
	collectTsFiles(root, files);

	const fileSet = new Set(files.map(normalizePath));
	const graph = new Map<string, string[]>();

	for (const file of files) {
		const deps: string[] = [];
		for (const spec of parseLocalImports(file)) {
			const resolved = tryResolveLocalImport(file, spec);
			if (resolved && fileSet.has(resolved)) {
				deps.push(resolved);
			}
		}
		graph.set(file, deps);
	}

	const state = new Map<string, number>(); // 0 unvisited, 1 visiting, 2 done
	const stack: string[] = [];
	const stackIndex = new Map<string, number>();
	const cycles: string[][] = [];
	const seen = new Set<string>();

	function dfs(node: string): void {
		state.set(node, 1);
		stackIndex.set(node, stack.length);
		stack.push(node);

		for (const next of graph.get(node) ?? []) {
			const s = state.get(next) ?? 0;
			if (s === 0) {
				dfs(next);
			} else if (s === 1) {
				const idx = stackIndex.get(next);
				if (idx !== undefined) {
					const cycle = stack.slice(idx).concat(next);
					const key = canonicalCycle(cycle);
					if (!seen.has(key)) {
						seen.add(key);
						cycles.push(cycle);
					}
				}
			}
		}

		stack.pop();
		stackIndex.delete(node);
		state.set(node, 2);
	}

	for (const file of files) {
		if ((state.get(file) ?? 0) === 0) {
			dfs(file);
		}
	}

	return cycles;
}

export function runCli(args: readonly string[]): number {
	const rootDir = args[0] ?? process.cwd();
	let cycles: string[][];
	try {
		cycles = detectCycles(rootDir);
	} catch (err) {
		const message = err instanceof Error ? err.message : String(err);
		console.error(`Error: ${message}`);
		return 2;
	}

	const root = normalizePath(rootDir);

	if (cycles.length === 0) {
		console.log('No circular dependencies found.');
		return 0;
	}

	for (const cycle of cycles) {
		const printable = cycle.map((p) => path.relative(root, p) || '.');
		console.log(printable.join(' -> '));
	}

	return 1;
}

export function dijkstraShortestPath(
	nodeCount: number,
	edges: readonly (readonly [number, number, number])[],
	start: number,
	end: number
): number | null {
	if (nodeCount <= 0) return null;
	if (start < 0 || start >= nodeCount || end < 0 || end >= nodeCount) return null;
	if (start === end) return 0;

	const adj: Array<Array<readonly [number, number]>> = Array.from({ length: nodeCount }, () => []);

	for (const [from, to, weight] of edges) {
		if (from < 0 || from >= nodeCount || to < 0 || to >= nodeCount) continue;
		if (weight < 0) continue;
		adj[from].push([to, weight]);
	}

	const dist: number[] = Array(nodeCount).fill(Infinity);
	const visited: boolean[] = Array(nodeCount).fill(false);
	dist[start] = 0;

	for (let i = 0; i < nodeCount; i++) {
		let u = -1;
		let best = Infinity;

		for (let v = 0; v < nodeCount; v++) {
			if (!visited[v] && dist[v] < best) {
				best = dist[v];
				u = v;
			}
		}

		if (u === -1 || best === Infinity) break;
		if (u === end) break;

		visited[u] = true;

		for (const [v, w] of adj[u]) {
			const nd = dist[u] + w;
			if (nd < dist[v]) dist[v] = nd;
		}
	}

	return dist[end] === Infinity ? null : dist[end];
}

export function fftBigintMultiplyDigitArrays(a: number[], b: number[]): number[] {
	const normalize = (arr: number[]): number[] => {
		let i = 0;
		while (i < arr.length - 1 && arr[i] === 0) i++;
		return arr.slice(i);
	};

	const A = normalize(a);
	const B = normalize(b);

	if (A.length === 0 || B.length === 0) return [0];
	if ((A.length === 1 && A[0] === 0) || (B.length === 1 && B[0] === 0)) return [0];

	// Use convolution-style schoolbook multiplication over base-10 digits.
	// Digits are big-endian, so multiply from right to left.
	const n = A.length;
	const m = B.length;
	const res = new Array<number>(n + m).fill(0);

	for (let i = n - 1; i >= 0; i--) {
		const ai = A[i];
		for (let j = m - 1; j >= 0; j--) {
			res[i + j + 1] += ai * B[j];
		}
	}

	// Carry propagation in base 10.
	for (let k = res.length - 1; k > 0; k--) {
		const carry = Math.floor(res[k] / 10);
		res[k] %= 10;
		res[k - 1] += carry;
	}

	// Handle potential extra carries at the front.
	while (res[0] >= 10) {
		const carry = Math.floor(res[0] / 10);
		res[0] %= 10;
		res.unshift(carry);
	}

	// Trim leading zeros.
	let p = 0;
	while (p < res.length - 1 && res[p] === 0) p++;
	return res.slice(p);
}

export function fibonacci(n: number): number {
	if (n < 0 || !Number.isInteger(n)) {
		throw new Error('n must be a non-negative integer');
	}

	if (n === 0) return 0;
	if (n === 1) return 1;

	let prev = 0;
	let curr = 1;

	for (let i = 2; i <= n; i++) {
		const next = prev + curr;
		prev = curr;
		curr = next;
	}

	return curr;
}

export function groupAnagrams(words: string[]): string[][] {
	const groups: string[][] = [];
	const indexByKey = new Map<string, number>();

	for (const word of words) {
		const key = word.split('').sort().join('');
		const existingIndex = indexByKey.get(key);

		if (existingIndex === undefined) {
			indexByKey.set(key, groups.length);
			groups.push([word]);
		} else {
			groups[existingIndex].push(word);
		}
	}

	return groups;
}

export function integerBreakMaxProduct(n: number): number {
	if (n <= 3) return n - 1;

	let product = 1;
	while (n > 4) {
		product *= 3;
		n -= 3;
	}
	return product * n;
}

export function longestCommonSubsequence(a: string, b: string): number {
	const m = a.length;
	const n = b.length;

	const dp: number[][] = Array.from({ length: m + 1 }, () => Array(n + 1).fill(0));

	for (let i = 1; i <= m; i++) {
		for (let j = 1; j <= n; j++) {
			if (a[i - 1] === b[j - 1]) {
				dp[i][j] = dp[i - 1][j - 1] + 1;
			} else {
				dp[i][j] = Math.max(dp[i - 1][j], dp[i][j - 1]);
			}
		}
	}

	return dp[m][n];
}

export function longestSubstringNoRepeat(input: string): number {
	let left = 0;
	let maxLen = 0;
	const lastSeen = new Map<string, number>();

	for (let right = 0; right < input.length; right++) {
		const ch = input[right];
		const prevIndex = lastSeen.get(ch);

		if (prevIndex !== undefined && prevIndex >= left) {
			left = prevIndex + 1;
		}

		lastSeen.set(ch, right);
		const currentLen = right - left + 1;
		if (currentLen > maxLen) {
			maxLen = currentLen;
		}
	}

	return maxLen;
}

export function lruCache(
	capacity: number,
	operations: readonly (readonly ['get' | 'put', number, number?])[],
): (number | null)[] {
	const result: (number | null)[] = [];

	if (capacity <= 0) {
		for (const [op] of operations) {
			result.push(op === 'get' ? -1 : null);
		}
		return result;
	}

	const map = new Map<number, number>();

	for (const operation of operations) {
		const [type, key, value] = operation;

		if (type === 'get') {
			if (!map.has(key)) {
				result.push(-1);
				continue;
			}
			const val = map.get(key)!;
			map.delete(key);
			map.set(key, val);
			result.push(val);
		} else {
			if (map.has(key)) {
				map.delete(key);
			}
			map.set(key, value as number);

			if (map.size > capacity) {
				const lruKey = map.keys().next().value as number;
				map.delete(lruKey);
			}

			result.push(null);
		}
	}

	return result;
}

export function mergeIntervals(intervals: [number, number][]): [number, number][] {
	if (intervals.length <= 1) {
		return [...intervals];
	}

	const sorted = [...intervals].sort((a, b) => a[0] - b[0]);
	const merged: [number, number][] = [sorted[0].slice() as [number, number]];

	for (let i = 1; i < sorted.length; i++) {
		const [currentStart, currentEnd] = sorted[i];
		const last = merged[merged.length - 1];

		if (currentStart <= last[1]) {
			last[1] = Math.max(last[1], currentEnd);
		} else {
			merged.push([currentStart, currentEnd]);
		}
	}

	return merged;
}

type ListNode = { value: number; next: ListNode | null };

function splitList(head: ListNode): [ListNode, ListNode | null] {
	let slow: ListNode = head;
	let fast: ListNode | null = head.next;

	while (fast !== null && fast.next !== null) {
		slow = slow.next as ListNode;
		fast = fast.next.next;
	}

	const mid = slow.next;
	slow.next = null;
	return [head, mid];
}

function mergeSortedLists(a: ListNode | null, b: ListNode | null): ListNode | null {
	const dummy: ListNode = { value: 0, next: null };
	let tail: ListNode = dummy;

	let left = a;
	let right = b;

	while (left !== null && right !== null) {
		if (left.value <= right.value) {
			tail.next = left;
			left = left.next;
		} else {
			tail.next = right;
			right = right.next;
		}
		tail = tail.next as ListNode;
	}

	tail.next = left !== null ? left : right;
	return dummy.next;
}

export function mergeSortLinkedList(
	head: { value: number; next: any } | null
): { value: number; next: any } | null {
	const nodeHead = head as ListNode | null;
	if (nodeHead === null || nodeHead.next === null) return nodeHead;

	const [leftHead, rightHead] = splitList(nodeHead);
	const leftSorted = mergeSortLinkedList(leftHead) as ListNode | null;
	const rightSorted = mergeSortLinkedList(rightHead as ListNode | null) as ListNode | null;

	return mergeSortedLists(leftSorted, rightSorted);
}

export function minStack(
	operations: readonly (readonly ['push' | 'pop' | 'top' | 'getMin', number?])[],
): (number | null)[] {
	const stack: number[] = [];
	const minStackValues: number[] = [];
	const result: (number | null)[] = [];

	for (const [op, value] of operations) {
		switch (op) {
			case 'push': {
				if (value === undefined) {
					result.push(null);
					break;
				}
				stack.push(value);
				if (minStackValues.length === 0 || value <= minStackValues[minStackValues.length - 1]) {
					minStackValues.push(value);
				}
				result.push(null);
				break;
			}
			case 'pop': {
				if (stack.length === 0) {
					result.push(null);
					break;
				}
				const popped = stack.pop() as number;
				if (popped === minStackValues[minStackValues.length - 1]) {
					minStackValues.pop();
				}
				result.push(popped);
				break;
			}
			case 'top': {
				result.push(stack.length ? stack[stack.length - 1] : null);
				break;
			}
			case 'getMin': {
				result.push(minStackValues.length ? minStackValues[minStackValues.length - 1] : null);
				break;
			}
		}
	}

	return result;
}

export function murmurhash3(str: string, seed: number): number {
	let h1 = seed >>> 0;
	const c1 = 0xcc9e2d51;
	const c2 = 0x1b873593;

	const len = str.length;
	let i = 0;

	while (i + 1 < len) {
		let k1 = (str.charCodeAt(i) & 0xffff) | ((str.charCodeAt(i + 1) & 0xffff) << 16);
		i += 2;

		k1 = Math.imul(k1, c1);
		k1 = (k1 << 15) | (k1 >>> 17);
		k1 = Math.imul(k1, c2);

		h1 ^= k1;
		h1 = (h1 << 13) | (h1 >>> 19);
		h1 = (Math.imul(h1, 5) + 0xe6546b64) >>> 0;
	}

	if (i < len) {
		let k1 = str.charCodeAt(i) & 0xffff;
		k1 = Math.imul(k1, c1);
		k1 = (k1 << 15) | (k1 >>> 17);
		k1 = Math.imul(k1, c2);
		h1 ^= k1;
	}

	h1 ^= len * 2;

	h1 ^= h1 >>> 16;
	h1 = Math.imul(h1, 0x85ebca6b);
	h1 ^= h1 >>> 13;
	h1 = Math.imul(h1, 0xc2b2ae35);
	h1 ^= h1 >>> 16;

	return h1 >>> 0;
}

export function numberOfIslands(grid: string[][]): number {
	if (grid.length === 0 || grid[0].length === 0) return 0;

	const rows = grid.length;
	const cols = grid[0].length;
	let count = 0;

	const dfs = (r: number, c: number): void => {
		if (r < 0 || r >= rows || c < 0 || c >= cols || grid[r][c] !== '1') return;
		grid[r][c] = '0';
		dfs(r + 1, c);
		dfs(r - 1, c);
		dfs(r, c + 1);
		dfs(r, c - 1);
	};

	for (let r = 0; r < rows; r++) {
		for (let c = 0; c < cols; c++) {
			if (grid[r][c] === '1') {
				count++;
				dfs(r, c);
			}
		}
	}

	return count;
}

export function productOfArrayExceptSelf(values: number[]): number[] {
	const n = values.length;
	const result = new Array<number>(n).fill(1);

	let prefix = 1;
	for (let i = 0; i < n; i++) {
		result[i] = prefix;
		prefix *= values[i];
	}

	let suffix = 1;
	for (let i = n - 1; i >= 0; i--) {
		result[i] *= suffix;
		suffix *= values[i];
	}

	return result;
}

export function quickselectKthSmallest(values: number[], k: number): number {
	if (!Number.isInteger(k) || k < 1 || k > values.length) {
		throw new RangeError('k is out of bounds');
	}
	if (values.length === 0) {
		throw new RangeError('Cannot select from an empty array');
	}

	const arr = values.slice();
	const targetIndex = k - 1;

	let left = 0;
	let right = arr.length - 1;

	while (left <= right) {
		const pivotIndex = partition(arr, left, right);

		if (pivotIndex === targetIndex) {
			return arr[pivotIndex];
		}
		if (pivotIndex < targetIndex) {
			left = pivotIndex + 1;
		} else {
			right = pivotIndex - 1;
		}
	}

	throw new Error('Unexpected quickselect state');
}

function partition(arr: number[], left: number, right: number): number {
	const pivotIndex = left + Math.floor(Math.random() * (right - left + 1));
	swap(arr, pivotIndex, right);

	const pivotValue = arr[right];
	let storeIndex = left;

	for (let i = left; i < right; i++) {
		if (arr[i] < pivotValue) {
			swap(arr, i, storeIndex);
			storeIndex++;
		}
	}

	swap(arr, storeIndex, right);
	return storeIndex;
}

function swap(arr: number[], i: number, j: number): void {
	const temp = arr[i];
	arr[i] = arr[j];
	arr[j] = temp;
}

export function quicksort(arr: number[]): number[] {
	if (arr.length <= 1) {
		return [...arr];
	}

	const pivot = arr[Math.floor(arr.length / 2)];
	const less: number[] = [];
	const equal: number[] = [];
	const greater: number[] = [];

	for (const value of arr) {
		if (value < pivot) {
			less.push(value);
		} else if (value > pivot) {
			greater.push(value);
		} else {
			equal.push(value);
		}
	}

	return [...quicksort(less), ...equal, ...quicksort(greater)];
}

export function topKFrequent(values: number[], k: number): number[] {
	if (k <= 0 || values.length === 0) return [];

	const frequency = new Map<number, number>();
	for (const value of values) {
		frequency.set(value, (frequency.get(value) ?? 0) + 1);
	}

	return [...frequency.entries()]
		.sort((a, b) => {
			if (b[1] !== a[1]) return b[1] - a[1];
			return a[0] - b[0];
		})
		.slice(0, k)
		.map(([value]) => value);
}

export function toyRsaBigint(
	p: bigint,
	q: bigint,
	e: bigint,
	message: bigint
): {
	publicKey: { n: bigint; e: bigint };
	privateKey: { n: bigint; d: bigint };
	cipher: bigint;
	decrypted: bigint;
} {
	const n = p * q;
	const phi = (p - 1n) * (q - 1n);

	const mod = (a: bigint, m: bigint): bigint => {
		const r = a % m;
		return r >= 0n ? r : r + m;
	};

	const gcd = (a: bigint, b: bigint): bigint => {
		let x = a < 0n ? -a : a;
		let y = b < 0n ? -b : b;
		while (y !== 0n) {
			const t = x % y;
			x = y;
			y = t;
		}
		return x;
	};

	const extendedGcd = (a: bigint, b: bigint): { g: bigint; x: bigint; y: bigint } => {
		let oldR = a;
		let r = b;
		let oldS = 1n;
		let s = 0n;
		let oldT = 0n;
		let t = 1n;

		while (r !== 0n) {
			const qv = oldR / r;
			[oldR, r] = [r, oldR - qv * r];
			[oldS, s] = [s, oldS - qv * s];
			[oldT, t] = [t, oldT - qv * t];
		}

		return { g: oldR, x: oldS, y: oldT };
	};

	const modInverse = (a: bigint, m: bigint): bigint => {
		const { g, x } = extendedGcd(a, m);
		if (g !== 1n && g !== -1n) {
			throw new Error('e and phi(n) must be coprime');
		}
		return mod(x, m);
	};

	const modPow = (base: bigint, exp: bigint, m: bigint): bigint => {
		if (m === 1n) return 0n;
		let result = 1n;
		let b = mod(base, m);
		let eexp = exp;
		while (eexp > 0n) {
			if ((eexp & 1n) === 1n) result = (result * b) % m;
			b = (b * b) % m;
			eexp >>= 1n;
		}
		return result;
	};

	if (p <= 1n || q <= 1n) throw new Error('p and q must be > 1');
	if (e <= 1n) throw new Error('e must be > 1');
	if (message < 0n || message >= n) throw new Error('message must satisfy 0 <= message < n');
	if (gcd(e, phi) !== 1n) throw new Error('e and phi(n) must be coprime');

	const d = modInverse(e, phi);
	const cipher = modPow(message, e, n);
	const decrypted = modPow(cipher, d, n);

	return {
		publicKey: { n, e },
		privateKey: { n, d },
		cipher,
		decrypted,
	};
}

export function twoSum(nums: number[], target: number): [number, number] | null {
	const indexByValue = new Map<number, number>();

	for (let i = 0; i < nums.length; i++) {
		const value = nums[i];
		const complement = target - value;

		if (indexByValue.has(complement)) {
			return [indexByValue.get(complement) as number, i];
		}

		indexByValue.set(value, i);
	}

	return null;
}

export function unionFindConnectedComponentsOnline(
	n: number,
	operations: readonly (readonly [number, number])[],
): number[] {
	const parent: number[] = Array.from({ length: n }, (_, i) => i);
	const size: number[] = Array(n).fill(1);
	let components = n;
	const result: number[] = [];

	const find = (x: number): number => {
		let root = x;
		while (parent[root] !== root) root = parent[root];
		while (parent[x] !== x) {
			const next = parent[x];
			parent[x] = root;
			x = next;
		}
		return root;
	};

	for (const [a, b] of operations) {
		const ra = find(a);
		const rb = find(b);
		if (ra !== rb) {
			if (size[ra] < size[rb]) {
				parent[ra] = rb;
				size[rb] += size[ra];
			} else {
				parent[rb] = ra;
				size[ra] += size[rb];
			}
			components--;
		}
		result.push(components);
	}

	return result;
}

export function validParentheses(input: string): boolean {
	const stack: string[] = [];
	const closingToOpening: Record<string, string> = {
		')': '(',
		']': '[',
		'}': '{',
	};

	for (const ch of input) {
		if (ch === '(' || ch === '[' || ch === '{') {
			stack.push(ch);
		} else if (ch in closingToOpening) {
			const expectedOpen = closingToOpening[ch];
			const actualOpen = stack.pop();
			if (actualOpen !== expectedOpen) return false;
		}
	}

	return stack.length === 0;
}

.hamburger-btn {
