type AVLNode = {
	value: number;
	height: number;
	left: AVLNode | null;
	right: AVLNode | null;
};

function getHeight(node: AVLNode | null): number {
	return node ? node.height : 0;
}

function updateHeight(node: AVLNode): void {
	node.height = 1 + Math.max(getHeight(node.left), getHeight(node.right));
}

function getBalance(node: AVLNode): number {
	return getHeight(node.left) - getHeight(node.right);
}

function rotateRight(y: AVLNode): AVLNode {
	const x = y.left as AVLNode;
	const t2 = x.right;

	x.right = y;
	y.left = t2;

	updateHeight(y);
	updateHeight(x);

	return x;
}

function rotateLeft(x: AVLNode): AVLNode {
	const y = x.right as AVLNode;
	const t2 = y.left;

	y.left = x;
	x.right = t2;

	updateHeight(x);
	updateHeight(y);

	return y;
}

function insert(node: AVLNode | null, value: number): AVLNode {
	if (!node) {
		return { value, height: 1, left: null, right: null };
	}

	if (value < node.value) {
		node.left = insert(node.left, value);
	} else if (value > node.value) {
		node.right = insert(node.right, value);
	} else {
		return node;
	}

	updateHeight(node);
	const balance = getBalance(node);

	if (balance > 1 && value < (node.left as AVLNode).value) {
		return rotateRight(node);
	}

	if (balance < -1 && value > (node.right as AVLNode).value) {
		return rotateLeft(node);
	}

	if (balance > 1 && value > (node.left as AVLNode).value) {
		node.left = rotateLeft(node.left as AVLNode);
		return rotateRight(node);
	}

	if (balance < -1 && value < (node.right as AVLNode).value) {
		node.right = rotateRight(node.right as AVLNode);
		return rotateLeft(node);
	}

	return node;
}

export function avlTreeInsertRebalance(values: number[]): { value: number; height: number; left: any; right: any } | null {
	let root: AVLNode | null = null;
	for (const value of values) {
		root = insert(root, value);
	}
	return root;
}

class BStarNode {
	keys: number[] = [];
	children: BStarNode[] = [];
	leaf: boolean;

	constructor(leaf: boolean) {
		this.leaf = leaf;
	}
}

export function createBStarTree(t: number): {
	insert: (key: number) => void;
	search: (key: number) => boolean;
	delete: (key: number) => void;
	keys: () => number[];
} {
	if (!Number.isInteger(t) || t < 2) {
		throw new Error('t must be an integer >= 2');
	}

	const minKeys = t - 1;
	const maxKeys = 2 * t - 1;

	let root = new BStarNode(true);

	function findKey(node: BStarNode, key: number): number {
		let idx = 0;
		while (idx < node.keys.length && node.keys[idx] < key) idx++;
		return idx;
	}

	function searchNode(node: BStarNode, key: number): boolean {
		const i = findKey(node, key);
		if (i < node.keys.length && node.keys[i] === key) return true;
		if (node.leaf) return false;
		return searchNode(node.children[i], key);
	}

	function splitChild(parent: BStarNode, i: number): void {
		const y = parent.children[i];
		const z = new BStarNode(y.leaf);

		const mid = t - 1;
		const up = y.keys[mid];

		z.keys = y.keys.slice(mid + 1);
		y.keys = y.keys.slice(0, mid);

		if (!y.leaf) {
			z.children = y.children.slice(mid + 1);
			y.children = y.children.slice(0, mid + 1);
		}

		parent.children.splice(i + 1, 0, z);
		parent.keys.splice(i, 0, up);
	}

	function tryRedistribute(parent: BStarNode, childIndex: number): boolean {
		const child = parent.children[childIndex];

		if (childIndex > 0) {
			const left = parent.children[childIndex - 1];
			if (left.keys.length < maxKeys) {
				left.keys.push(parent.keys[childIndex - 1]);
				parent.keys[childIndex - 1] = child.keys.shift() as number;
				if (!child.leaf) {
					left.children.push(child.children.shift() as BStarNode);
				}
				return true;
			}
		}

		if (childIndex < parent.children.length - 1) {
			const right = parent.children[childIndex + 1];
			if (right.keys.length < maxKeys) {
				right.keys.unshift(parent.keys[childIndex]);
				parent.keys[childIndex] = child.keys.pop() as number;
				if (!child.leaf) {
					right.children.unshift(child.children.pop() as BStarNode);
				}
				return true;
			}
		}

		return false;
	}

	function insertNonFull(node: BStarNode, key: number): void {
		let i = node.keys.length - 1;

		if (node.leaf) {
			while (i >= 0 && key < node.keys[i]) i--;
			if (i >= 0 && node.keys[i] === key) return;
			if (i + 1 < node.keys.length && node.keys[i + 1] === key) return;
			node.keys.splice(i + 1, 0, key);
			return;
		}

		while (i >= 0 && key < node.keys[i]) i--;
		i++;

		if (i < node.keys.length && node.keys[i] === key) return;

		if (node.children[i].keys.length === maxKeys) {
			if (!tryRedistribute(node, i)) {
				splitChild(node, i);
				if (key > node.keys[i]) i++;
				else if (key === node.keys[i]) return;
			}
		}

		insertNonFull(node.children[i], key);
	}

	function getPredecessor(node: BStarNode): number {
		let cur = node;
		while (!cur.leaf) cur = cur.children[cur.children.length - 1];
		return cur.keys[cur.keys.length - 1];
	}

	function getSuccessor(node: BStarNode): number {
		let cur = node;
		while (!cur.leaf) cur = cur.children[0];
		return cur.keys[0];
	}

	function merge(parent: BStarNode, idx: number): void {
		const left = parent.children[idx];
		const right = parent.children[idx + 1];

		left.keys.push(parent.keys[idx], ...right.keys);
		if (!left.leaf) left.children.push(...right.children);

		parent.keys.splice(idx, 1);
		parent.children.splice(idx + 1, 1);
	}

	function borrowFromPrev(parent: BStarNode, idx: number): void {
		const child = parent.children[idx];
		const sibling = parent.children[idx - 1];

		child.keys.unshift(parent.keys[idx - 1]);
		parent.keys[idx - 1] = sibling.keys.pop() as number;

		if (!child.leaf) {
			child.children.unshift(sibling.children.pop() as BStarNode);
		}
	}

	function borrowFromNext(parent: BStarNode, idx: number): void {
		const child = parent.children[idx];
		const sibling = parent.children[idx + 1];

		child.keys.push(parent.keys[idx]);
		parent.keys[idx] = sibling.keys.shift() as number;

		if (!child.leaf) {
			child.children.push(sibling.children.shift() as BStarNode);
		}
	}

	function fill(parent: BStarNode, idx: number): void {
		if (idx > 0 && parent.children[idx - 1].keys.length >= t) {
			borrowFromPrev(parent, idx);
		} else if (idx < parent.children.length - 1 && parent.children[idx + 1].keys.length >= t) {
			borrowFromNext(parent, idx);
		} else {
			if (idx < parent.children.length - 1) merge(parent, idx);
			else merge(parent, idx - 1);
		}
	}

	function removeFromNode(node: BStarNode, key: number): void {
		const idx = findKey(node, key);

		if (idx < node.keys.length && node.keys[idx] === key) {
			if (node.leaf) {
				node.keys.splice(idx, 1);
				return;
			}

			const leftChild = node.children[idx];
			const rightChild = node.children[idx + 1];

			if (leftChild.keys.length >= t) {
				const pred = getPredecessor(leftChild);
				node.keys[idx] = pred;
				removeFromNode(leftChild, pred);
			} else if (rightChild.keys.length >= t) {
				const succ = getSuccessor(rightChild);
				node.keys[idx] = succ;
				removeFromNode(rightChild, succ);
			} else {
				merge(node, idx);
				removeFromNode(leftChild, key);
			}
		} else {
			if (node.leaf) return;

			let childIdx = idx;

			if (node.children[childIdx].keys.length === minKeys) {
				fill(node, childIdx);
				if (childIdx > node.keys.length) childIdx--;
			}

			removeFromNode(node.children[childIdx], key);
		}
	}

	function traverse(node: BStarNode, out: number[]): void {
		for (let i = 0; i < node.keys.length; i++) {
			if (!node.leaf) traverse(node.children[i], out);
			out.push(node.keys[i]);
		}
		if (!node.leaf) traverse(node.children[node.keys.length], out);
	}

	return {
		insert(key: number): void {
			if (searchNode(root, key)) return;

			if (root.keys.length === maxKeys) {
				const s = new BStarNode(false);
				s.children.push(root);

				if (!tryRedistribute(s, 0)) {
					splitChild(s, 0);
				}
				root = s;
			}

			insertNonFull(root, key);
		},

		search(key: number): boolean {
			return searchNode(root, key);
		},

		delete(key: number): void {
			if (!root) return;
			removeFromNode(root, key);

			if (!root.leaf && root.keys.length === 0) {
				root = root.children[0];
			}
		},

		keys(): number[] {
			const out: number[] = [];
			traverse(root, out);
			return out;
		},
	};
}

type BTreeNode = {
	keys: number[];
	children: BTreeNode[];
	leaf: boolean;
};

export function createBTree(t: number): {
	insert: (key: number) => void;
	search: (key: number) => boolean;
	delete: (key: number) => void;
	keys: () => number[];
} {
	if (!Number.isInteger(t) || t < 2) {
		throw new Error('t must be an integer >= 2');
	}

	let root: BTreeNode = makeNode(true);

	function makeNode(leaf: boolean): BTreeNode {
		return { keys: [], children: [], leaf };
	}

	function findKeyIndex(node: BTreeNode, key: number): number {
		let i = 0;
		while (i < node.keys.length && node.keys[i] < key) i++;
		return i;
	}

	function searchNode(node: BTreeNode, key: number): boolean {
		const i = findKeyIndex(node, key);
		if (i < node.keys.length && node.keys[i] === key) return true;
		if (node.leaf) return false;
		return searchNode(node.children[i], key);
	}

	function splitChild(parent: BTreeNode, i: number): void {
		const y = parent.children[i];
		const z = makeNode(y.leaf);

		const median = y.keys[t - 1];

		z.keys = y.keys.slice(t);
		y.keys = y.keys.slice(0, t - 1);

		if (!y.leaf) {
			z.children = y.children.slice(t);
			y.children = y.children.slice(0, t);
		}

		parent.children.splice(i + 1, 0, z);
		parent.keys.splice(i, 0, median);
	}

	function insertNonFull(node: BTreeNode, key: number): void {
		let i = node.keys.length - 1;

		if (node.leaf) {
			while (i >= 0 && key < node.keys[i]) i--;
			if (i >= 0 && node.keys[i] === key) return;
			if (i + 1 < node.keys.length && node.keys[i + 1] === key) return;
			node.keys.splice(i + 1, 0, key);
			return;
		}

		while (i >= 0 && key < node.keys[i]) i--;
		i++;

		if (i < node.keys.length && node.keys[i] === key) return;
		if (i - 1 >= 0 && node.keys[i - 1] === key) return;

		if (node.children[i].keys.length === 2 * t - 1) {
			splitChild(node, i);
			if (key === node.keys[i]) return;
			if (key > node.keys[i]) i++;
		}

		insertNonFull(node.children[i], key);
	}

	function getPredecessor(node: BTreeNode): number {
		let cur = node;
		while (!cur.leaf) cur = cur.children[cur.children.length - 1];
		return cur.keys[cur.keys.length - 1];
	}

	function getSuccessor(node: BTreeNode): number {
		let cur = node;
		while (!cur.leaf) cur = cur.children[0];
		return cur.keys[0];
	}

	function mergeChildren(parent: BTreeNode, idx: number): void {
		const left = parent.children[idx];
		const right = parent.children[idx + 1];
		left.keys.push(parent.keys[idx], ...right.keys);
		if (!left.leaf) left.children.push(...right.children);
		parent.keys.splice(idx, 1);
		parent.children.splice(idx + 1, 1);
	}

	function borrowFromPrev(parent: BTreeNode, idx: number): void {
		const child = parent.children[idx];
		const sibling = parent.children[idx - 1];

		child.keys.unshift(parent.keys[idx - 1]);
		if (!child.leaf) {
			child.children.unshift(sibling.children.pop() as BTreeNode);
		}
		parent.keys[idx - 1] = sibling.keys.pop() as number;
	}

	function borrowFromNext(parent: BTreeNode, idx: number): void {
		const child = parent.children[idx];
		const sibling = parent.children[idx + 1];

		child.keys.push(parent.keys[idx]);
		if (!child.leaf) {
			child.children.push(sibling.children.shift() as BTreeNode);
		}
		parent.keys[idx] = sibling.keys.shift() as number;
	}

	function fillChild(parent: BTreeNode, idx: number): void {
		if (idx > 0 && parent.children[idx - 1].keys.length >= t) {
			borrowFromPrev(parent, idx);
		} else if (idx < parent.children.length - 1 && parent.children[idx + 1].keys.length >= t) {
			borrowFromNext(parent, idx);
		} else {
			if (idx < parent.children.length - 1) {
				mergeChildren(parent, idx);
			} else {
				mergeChildren(parent, idx - 1);
			}
		}
	}

	function deleteFromNode(node: BTreeNode, key: number): void {
		let idx = findKeyIndex(node, key);

		if (idx < node.keys.length && node.keys[idx] === key) {
			if (node.leaf) {
				node.keys.splice(idx, 1);
				return;
			}

			const leftChild = node.children[idx];
			const rightChild = node.children[idx + 1];

			if (leftChild.keys.length >= t) {
				const pred = getPredecessor(leftChild);
				node.keys[idx] = pred;
				deleteFromNode(leftChild, pred);
			} else if (rightChild.keys.length >= t) {
				const succ = getSuccessor(rightChild);
				node.keys[idx] = succ;
				deleteFromNode(rightChild, succ);
			} else {
				mergeChildren(node, idx);
				deleteFromNode(leftChild, key);
			}
			return;
		}

		if (node.leaf) return;

		let childIdx = idx;
		if (node.children[childIdx].keys.length === t - 1) {
			fillChild(node, childIdx);
			if (childIdx > node.keys.length) childIdx = node.keys.length;
		}

		deleteFromNode(node.children[childIdx], key);
	}

	function inorder(node: BTreeNode, out: number[]): void {
		for (let i = 0; i < node.keys.length; i++) {
			if (!node.leaf) inorder(node.children[i], out);
			out.push(node.keys[i]);
		}
		if (!node.leaf) inorder(node.children[node.keys.length], out);
	}

	return {
		insert(key: number): void {
			if (searchNode(root, key)) return;

			if (root.keys.length === 2 * t - 1) {
				const s = makeNode(false);
				s.children.push(root);
				splitChild(s, 0);
				root = s;
			}
			insertNonFull(root, key);
		},
		search(key: number): boolean {
			return searchNode(root, key);
		},
		delete(key: number): void {
			deleteFromNode(root, key);
			if (!root.leaf && root.keys.length === 0) {
				root = root.children[0];
			}
		},
		keys(): number[] {
			const out: number[] = [];
			inorder(root, out);
			return out;
		},
	};
}

export function bloomFilterNHashFunctions(
	size: number,
	hashCount: number,
	wordsToAdd: string[],
	queries: string[]
): boolean[] {
	const bitArray = new Array<boolean>(Math.max(0, size)).fill(false);

	const fnv1a32 = (str: string, seed: number): number => {
		let hash = (0x811c9dc5 ^ seed) >>> 0;
		for (let i = 0; i < str.length; i++) {
			hash ^= str.charCodeAt(i);
			hash = Math.imul(hash, 0x01000193) >>> 0;
		}
		return hash >>> 0;
	};

	const getHashes = (word: string): number[] => {
		if (size <= 0 || hashCount <= 0) return [];
		const h1 = fnv1a32(word, 0);
		let h2 = fnv1a32(word, 0x9e3779b9);
		if (h2 === 0) h2 = 1;
		const indices: number[] = [];
		for (let i = 0; i < hashCount; i++) {
			const combined = (h1 + Math.imul(i, h2)) >>> 0;
			indices.push(combined % size);
		}
		return indices;
	};

	for (const word of wordsToAdd) {
		for (const idx of getHashes(word)) {
			bitArray[idx] = true;
		}
	}

	const result: boolean[] = [];
	for (const q of queries) {
		const hashes = getHashes(q);
		let maybePresent = true;
		for (const idx of hashes) {
			if (!bitArray[idx]) {
				maybePresent = false;
				break;
			}
		}
		result.push(maybePresent);
	}

	return result;
}

export function detectCycleDirectedGraph(graph: Record<number, number[]>): boolean {
	const visited = new Set<number>();
	const inStack = new Set<number>();

	const nodes = new Set<number>();
	for (const [key, neighbors] of Object.entries(graph)) {
		const node = Number(key);
		nodes.add(node);
		for (const n of neighbors) nodes.add(n);
	}

	const dfs = (node: number): boolean => {
		if (inStack.has(node)) return true;
		if (visited.has(node)) return false;

		visited.add(node);
		inStack.add(node);

		const neighbors = graph[node] ?? [];
		for (const next of neighbors) {
			if (dfs(next)) return true;
		}

		inStack.delete(node);
		return false;
	};

	for (const node of nodes) {
		if (!visited.has(node) && dfs(node)) return true;
	}

	return false;
}

export function evaluateReversePolishNotation(tokens: string[]): number {
	const stack: number[] = [];

	for (const token of tokens) {
		if (token === '+' || token === '-' || token === '*' || token === '/') {
			const b = stack.pop();
			const a = stack.pop();

			if (a === undefined || b === undefined) {
				throw new Error('Invalid RPN expression');
			}

			let result: number;
			switch (token) {
				case '+':
					result = a + b;
					break;
				case '-':
					result = a - b;
					break;
				case '*':
					result = a * b;
					break;
				case '/':
					result = Math.trunc(a / b);
					break;
				default:
					throw new Error('Unsupported operator');
			}

			stack.push(result);
		} else {
			stack.push(Number(token));
		}
	}

	if (stack.length !== 1) {
		throw new Error('Invalid RPN expression');
	}

	return stack[0];
}

export function kLargestElementsInStream(stream: number[], k: number): number[][] {
	const result: number[][] = [];

	if (k <= 0) {
		for (let i = 0; i < stream.length; i++) {
			result.push([]);
		}
		return result;
	}

	const top: number[] = [];

	for (const value of stream) {
		let inserted = false;
		for (let i = 0; i < top.length; i++) {
			if (value > top[i]) {
				top.splice(i, 0, value);
				inserted = true;
				break;
			}
		}
		if (!inserted) {
			top.push(value);
		}

		if (top.length > k) {
			top.pop();
		}

		result.push([...top]);
	}

	return result;
}

export function reverseLinkedListInPlace(
	head: { value: number; next: any } | null
): { value: number; next: any } | null {
	let prev: { value: number; next: any } | null = null;
	let current = head;

	while (current !== null) {
		const nextNode = current.next;
		current.next = prev;
		prev = current;
		current = nextNode;
	}

	return prev;
}

export function trieAutocomplete(words: string[], prefixes: string[]): string[][] {
	type TrieNode = {
		children: Map<string, TrieNode>;
		isWord: boolean;
	};

	const root: TrieNode = { children: new Map(), isWord: false };

	for (const word of words) {
		let node = root;
		for (const ch of word) {
			let next = node.children.get(ch);
			if (!next) {
				next = { children: new Map(), isWord: false };
				node.children.set(ch, next);
			}
			node = next;
		}
		node.isWord = true;
	}

	function findNode(prefix: string): TrieNode | null {
		let node: TrieNode | undefined = root;
		for (const ch of prefix) {
			node = node.children.get(ch);
			if (!node) return null;
		}
		return node;
	}

	function collect(node: TrieNode, path: string, out: string[]): void {
		if (node.isWord) out.push(path);
		const keys = Array.from(node.children.keys()).sort();
		for (const ch of keys) {
			const child = node.children.get(ch)!;
			collect(child, path + ch, out);
		}
	}

	const result: string[][] = [];
	for (const prefix of prefixes) {
		const start = findNode(prefix);
		if (!start) {
			result.push([]);
			continue;
		}
		const matches: string[] = [];
		collect(start, prefix, matches);
		result.push(matches);
	}

	return result;
}

export function validateBinarySearchTree(root: { value: number; left: any; right: any } | null): boolean {
	function isValid(node: { value: number; left: any; right: any } | null, min: number, max: number): boolean {
		if (node === null) return true;
		if (node.value <= min || node.value >= max) return false;
		return isValid(node.left, min, node.value) && isValid(node.right, node.value, max);
	}

	return isValid(root, -Infinity, Infinity);
}

export function easterSunday(year: number): { month: number; day: number } {
	const a = year % 19;
	const b = Math.floor(year / 100);
	const c = year % 100;
	const d = Math.floor(b / 4);
	const e = b % 4;
	const f = Math.floor((b + 8) / 25);
	const g = Math.floor((b - f + 1) / 3);
	const h = (19 * a + b - d - g + 15) % 30;
	const i = Math.floor(c / 4);
	const k = c % 4;
	const l = (32 + 2 * e + 2 * i - h - k) % 7;
	const m = Math.floor((a + 11 * h + 22 * l) / 451);
	const month = Math.floor((h + l - 7 * m + 114) / 31);
	const day = ((h + l - 7 * m + 114) % 31) + 1;

	return { month, day };
}

export function getISOWeek(date: Date): { week: number; year: number } {
	const d = new Date(Date.UTC(date.getFullYear(), date.getMonth(), date.getDate()));
	const day = d.getUTCDay() || 7; // Monday=1 ... Sunday=7
	d.setUTCDate(d.getUTCDate() + 4 - day); // move to Thursday of current ISO week

	const isoYear = d.getUTCFullYear();
	const yearStart = new Date(Date.UTC(isoYear, 0, 1));
	const week = Math.ceil((((d.getTime() - yearStart.getTime()) / 86400000) + 1) / 7);

	return { week, year: isoYear };
}

export function validateDate(s: string): boolean {
	const match = /^(\d{4})-(\d{2})-(\d{2})$/.exec(s);
	if (!match) return false;

	const year = Number(match[1]);
	const month = Number(match[2]);
	const day = Number(match[3]);

	if (month < 1 || month > 12) return false;

	const isLeapYear =
		(year % 4 === 0 && year % 100 !== 0) || year % 400 === 0;

	const daysInMonth = [
		31,
		isLeapYear ? 29 : 28,
		31,
		30,
		31,
		30,
		31,
		31,
		30,
		31,
		30,
		31,
	];

	return day >= 1 && day <= daysInMonth[month - 1];
}

export const html06DialogModal = (): string => {
	return `<!doctype html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
  <title>Dialog Modal</title>
  <style>
    body { font-family: Arial, sans-serif; padding: 2rem; }
    dialog {
      border: none;
      border-radius: 8px;
      padding: 1rem 1.25rem;
      width: min(90vw, 420px);
      box-shadow: 0 10px 30px rgba(0,0,0,0.25);
    }
    dialog::backdrop { background: rgba(0, 0, 0, 0.45); }
    .row { display: flex; justify-content: flex-end; margin-top: 1rem; }
  </style>
</head>
<body>
  <button id="open-dialog" type="button">Open modal</button>

  <dialog id="modal" aria-labelledby="dialog-title" aria-describedby="dialog-description">
    <h2 id="dialog-title">Modal title</h2>
    <p id="dialog-description">This is an accessible modal using the native dialog element.</p>
    <div class="row">
      <button id="close-dialog" type="button" aria-label="Close dialog">Close</button>
    </div>
  </dialog>

  <script>
    const dialog = document.getElementById('modal');
    const openBtn = document.getElementById('open-dialog');
    const closeBtn = document.getElementById('close-dialog');

    const getFocusable = () => {
      return Array.from(
        dialog.querySelectorAll(
          'button, [href], input, select, textarea, [tabindex]:not([tabindex="-1"])'
        )
      ).filter(el => !el.hasAttribute('disabled') && el.getAttribute('aria-hidden') !== 'true');
    };

    openBtn.addEventListener('click', () => {
      dialog.showModal();
      const focusable = getFocusable();
      const first = focusable[0];
      first?.focus();
    });

    closeBtn.addEventListener('click', () => {
      dialog.close();
      openBtn.focus();
    });

    dialog.addEventListener('keydown', (event) => {
      if (event.key === 'Escape') {
        event.preventDefault();
        dialog.close();
        openBtn.focus();
        return;
      }

      if (event.key !== 'Tab') return;

      const focusable = getFocusable();
      const first = focusable[0];
      const last = focusable[focusable.length - 1];
      if (!first || !last) return;

      if (event.shiftKey && document.activeElement === first) {
        event.preventDefault();
        last.focus();
      } else if (!event.shiftKey && document.activeElement === last) {
        event.preventDefault();
        first.focus();
      }
    });

    dialog.addEventListener('click', (event) => {
      if (event.target === dialog) {
        dialog.close();
        openBtn.focus();
      }
    });
  </script>
</body>
