export function dateInputToIso(input: string): string | null {
	if (!/^\d{4}-\d{2}-\d{2}$/.test(input)) {
		return null;
	}

	const [yearStr, monthStr, dayStr] = input.split("-");
	const year = Number(yearStr);
	const month = Number(monthStr);
	const day = Number(dayStr);

	if (month < 1 || month > 12) return null;
	if (day < 1) return null;

	const isLeapYear =
		(year % 4 === 0 && year % 100 !== 0) || year % 400 === 0;

	const daysInMonth = [
		31,
		isLeapYear ? 29 : 28,
		31,
		30,
		31,
		30,
		31,
		31,
		30,
		31,
		30,
		31,
	];

	if (day > daysInMonth[month - 1]) return null;

	return `${yearStr}-${monthStr}-${dayStr}`;
}

export type Row = Record<string, string | number | boolean | null>;

function isPlainObject(value: unknown): value is Record<string, unknown> {
	return typeof value === 'object' && value !== null && !Array.isArray(value);
}

function assertValidTagName(name: string, label: string): void {
	if (typeof name !== 'string' || !name.trim()) {
		throw new Error(`${label} must be a non-empty string`);
	}
	const trimmed = name.trim();
	if (!/^[A-Za-z_][A-Za-z0-9._-]*$/.test(trimmed)) {
		throw new Error(`${label} is not a valid XML tag name`);
	}
}

function coercePrimitive(value: unknown): string | number | boolean | null {
	if (value === null) return null;
	const t = typeof value;
	if (t === 'string' || t === 'number' || t === 'boolean') {
		if (t === 'number' && !Number.isFinite(value as number)) {
			throw new Error('Row contains non-finite number');
		}
		return value as string | number | boolean;
	}
	throw new Error('Row values must be string, number, boolean, or null');
}

function assertValidRows(rows: Row[]): void {
	if (!Array.isArray(rows)) throw new Error('Rows must be an array');
	for (const row of rows) {
		if (!isPlainObject(row)) throw new Error('Each row must be an object');
		for (const [k, v] of Object.entries(row)) {
			if (!k) throw new Error('Column name cannot be empty');
			coercePrimitive(v);
		}
	}
}

function valueToString(value: string | number | boolean | null): string {
	return value === null ? '' : String(value);
}

function inferValue(text: string): string | number | boolean | null {
	const trimmed = text.trim();
	if (trimmed === '') return null;
	if (trimmed === 'true') return true;
	if (trimmed === 'false') return false;
	if (/^-?(?:0|[1-9]\d*)(?:\.\d+)?(?:[eE][+-]?\d+)?$/.test(trimmed)) {
		const n = Number(trimmed);
		if (Number.isFinite(n)) return n;
	}
	return text;
}

function escapeCsvField(value: string): string {
	if (/[",\n\r]/.test(value)) {
		return `"${value.replace(/"/g, '""')}"`;
	}
	return value;
}

function parseCsv(csv: string): string[][] {
	if (typeof csv !== 'string') throw new Error('CSV input must be a string');
	const rows: string[][] = [];
	let row: string[] = [];
	let field = '';
	let i = 0;
	let inQuotes = false;

	while (i < csv.length) {
		const ch = csv[i];

		if (inQuotes) {
			if (ch === '"') {
				if (i + 1 < csv.length && csv[i + 1] === '"') {
					field += '"';
					i += 2;
					continue;
				}
				inQuotes = false;
				i += 1;
				continue;
			}
			field += ch;
			i += 1;
			continue;
		}

		if (ch === '"') {
			inQuotes = true;
			i += 1;
			continue;
		}
		if (ch === ',') {
			row.push(field);
			field = '';
			i += 1;
			continue;
		}
		if (ch === '\n') {
			row.push(field);
			rows.push(row);
			row = [];
			field = '';
			i += 1;
			continue;
		}
		if (ch === '\r') {
			row.push(field);
			rows.push(row);
			row = [];
			field = '';
			i += 1;
			if (i < csv.length && csv[i] === '\n') i += 1;
			continue;
		}
		field += ch;
		i += 1;
	}

	if (inQuotes) throw new Error('Malformed CSV: unclosed quote');
	row.push(field);
	const hasContent = row.some((f) => f.length > 0) || rows.length > 0;
	if (hasContent) rows.push(row);

	return rows;
}

function toCsv(records: string[][]): string {
	return records.map((r) => r.map(escapeCsvField).join(',')).join('\n');
}

function escapeXml(text: string): string {
	return text
		.replace(/&/g, '&amp;')
		.replace(/</g, '&lt;')
		.replace(/>/g, '&gt;')
		.replace(/"/g, '&quot;')
		.replace(/'/g, '&apos;');
}

function unescapeXml(text: string): string {
	return text
		.replace(/&lt;/g, '<')
		.replace(/&gt;/g, '>')
		.replace(/&quot;/g, '"')
		.replace(/&apos;/g, "'")
		.replace(/&amp;/g, '&');
}

function collectColumns(rows: Row[]): string[] {
	const set = new Set<string>();
	for (const row of rows) {
		for (const key of Object.keys(row)) set.add(key);
	}
	return Array.from(set);
}

export function jsonToCsv(rows: Row[]): string {
	assertValidRows(rows);
	const columns = collectColumns(rows);
	if (columns.length === 0) return '';

	const records: string[][] = [columns];
	for (const row of rows) {
		records.push(columns.map((c) => valueToString((row as Record<string, string | number | boolean | null>)[c] ?? null)));
	}
	return toCsv(records);
}

export function csvToJson(csv: string): Row[] {
	const records = parseCsv(csv);
	if (records.length === 0) return [];

	const header = records[0];
	if (header.length === 0 || header.every((h) => h.trim() === '')) {
		throw new Error('CSV header is required');
	}
	for (const h of header) {
		if (!h) throw new Error('CSV header contains empty column name');
	}
	const uniq = new Set(header);
	if (uniq.size !== header.length) throw new Error('CSV header contains duplicate column names');

	const rows: Row[] = [];
	for (let i = 1; i < records.length; i++) {
		const rec = records[i];
		if (rec.length !== header.length) {
			throw new Error(`CSV row ${i + 1} has incorrect column count`);
		}
		const obj: Row = {};
		for (let j = 0; j < header.length; j++) {
			obj[header[j]] = inferValue(rec[j]);
		}
		rows.push(obj);
	}
	return rows;
}

export function jsonToXml(rows: Row[], rootElement: string, rowElement: string): string {
	assertValidRows(rows);
	assertValidTagName(rootElement, 'rootElement');
	assertValidTagName(rowElement, 'rowElement');

	const columns = collectColumns(rows);
	let out = `<${rootElement}>`;
	for (const row of rows) {
		out += `<${rowElement}>`;
		for (const col of columns) {
			assertValidTagName(col, `column name "${col}"`);
			const value = (row as Record<string, string | number | boolean | null>)[col] ?? null;
			out += `<${col}>${escapeXml(valueToString(value))}</${col}>`;
		}
		out += `</${rowElement}>`;
	}
	out += `</${rootElement}>`;
	return out;
}

export function xmlToJson(xml: string, rowElement: string): Row[] {
	if (typeof xml !== 'string') throw new Error('XML input must be a string');
	assertValidTagName(rowElement, 'rowElement');

	const rows: Row[] = [];
	const rowRegex = new RegExp(`<${rowElement}>([\\s\\S]*?)<\\/${rowElement}>`, 'g');
	let rowMatch: RegExpExecArray | null;

	while ((rowMatch = rowRegex.exec(xml)) !== null) {
		const inner = rowMatch[1];
		const obj: Row = {};
		const fieldRegex = /<([A-Za-z_][A-Za-z0-9._-]*)>([\s\S]*?)<\/\1>/g;
		let fieldMatch: RegExpExecArray | null;
		let consumed = '';
		while ((fieldMatch = fieldRegex.exec(inner)) !== null) {
			const key = fieldMatch[1];
			const raw = unescapeXml(fieldMatch[2]);
			obj[key] = inferValue(raw);
			consumed += fieldMatch[0];
		}
		if (inner.replace(/\s+/g, '') !== consumed.replace(/\s+/g, '')) {
			throw new Error('Malformed XML row content');
		}
		rows.push(obj);
	}

	if (rows.length === 0 && xml.includes(`<${rowElement}>`)) {
		throw new Error('Malformed XML');
	}
	return rows;
}

export function csvToXml(csv: string, rootElement: string, rowElement: string): string {
	return jsonToXml(csvToJson(csv), rootElement, rowElement);
}

export function xmlToCsv(xml: string, rowElement: string): string {
	return jsonToCsv(xmlToJson(xml, rowElement));
}

export function normalizeNumberInput(input: string | number | null): number | null {
	if (input === null) return null;

	if (typeof input === 'number') {
		return Number.isFinite(input) ? input : null;
	}

	const trimmed = input.trim();
	if (trimmed === '') return null;

	const parsed = Number(trimmed);
	return Number.isFinite(parsed) ? parsed : null;
}

export function parseIntStrict(input: string): number | null {
	const trimmed = input.trim();

	if (!/^-?\d+$/.test(trimmed)) {
		return null;
	}

	const value = Number.parseInt(trimmed, 10);
	return Number.isNaN(value) ? null : value;
}

export function queryParamCoercion(query: string): { page: number; limit: number; includeArchived: boolean } {
	const defaults = { page: 1, limit: 20, includeArchived: false };

	const raw = query.startsWith('?') ? query.slice(1) : query;
	const params = new URLSearchParams(raw);

	const pageRaw = params.get('page');
	const limitRaw = params.get('limit');
	const includeArchivedRaw = params.get('includeArchived');

	const pageNum = pageRaw !== null ? Number(pageRaw) : NaN;
	const limitNum = limitRaw !== null ? Number(limitRaw) : NaN;

	const page = Number.isInteger(pageNum) && pageNum > 0 ? pageNum : defaults.page;
	const limit = Number.isInteger(limitNum) && limitNum > 0 ? limitNum : defaults.limit;

	let includeArchived = defaults.includeArchived;
	if (includeArchivedRaw !== null) {
		const normalized = includeArchivedRaw.trim().toLowerCase();
		if (normalized === 'true') includeArchived = true;
		else if (normalized === 'false') includeArchived = false;
	}

	return { page, limit, includeArchived };
}

export function safeJsonParse(input: string): unknown {
	try {
		return JSON.parse(input);
	} catch {
		return null;
	}
}

export function toBooleanStrict(input: string): boolean | null {
	const normalized = input.trim().toLowerCase();

	if (normalized === 'true' || normalized === '1' || normalized === 'yes') {
		return true;
	}

	if (normalized === 'false' || normalized === '0' || normalized === 'no') {
		return false;
	}

	return null;
}

export function toNumber(s: string): number | null {
	const str = s.trim();
	if (str.length === 0) return null;

	let i = 0;
	let sign = 1;

	if (str[i] === '-') {
		sign = -1;
		i++;
		if (i >= str.length) return null;
	}

	let intPart = 0;
	let fracPart = 0;
	let fracDiv = 1;
	let hasDigit = false;
	let seenDot = false;

	for (; i < str.length; i++) {
		const ch = str[i];

		if (ch === '.') {
			if (seenDot) return null;
			seenDot = true;
			continue;
		}

		const code = ch.charCodeAt(0);
		if (code < 48 || code > 57) return null;

		hasDigit = true;
		const digit = code - 48;

		if (!seenDot) {
			intPart = intPart * 10 + digit;
		} else {
			fracPart = fracPart * 10 + digit;
			fracDiv *= 10;
		}
	}

	if (!hasDigit) return null;

	return sign * (intPart + fracPart / fracDiv);
}

export function toNumber(s: string): number | null {
	const trimmed = s.trim();
	if (trimmed.length === 0) return null;
	if (!/^[+-]?(?:\d+\.?\d*|\.\d+)$/.test(trimmed)) return null;

	const n = Number(trimmed);
	return Number.isFinite(n) ? n : null;
}

export function dedupe(values: number[]): number[] {
