export function fibonacci(n: number): number {
	const memo: Record<number, number> = {};

	function fib(x: number): number {
		if (x <= 1) {
			return x;
		}
		if (memo[x] !== undefined) {
			return memo[x];
		}
		memo[x] = fib(x - 1) + fib(x - 2);
		return memo[x];
	}

	return fib(n);
}

