import axios from 'axios';

type HeaderValue = string | number | boolean;
type HeadersMap = Record<string, HeaderValue>;
type QueryParams = Record<string, string | number | boolean | null | undefined>;

interface ConfigureOptions {
	baseURL: string;
	headers?: HeadersMap;
}

interface PostOptions {
	headers?: HeadersMap;
}

interface ParsedItem {
	id: string | number;
	label: string;
	meta: Record<string, unknown>;
}

let baseURL = '';
const defaultHeaders: HeadersMap = {};

export function configure(options: ConfigureOptions): void {
	baseURL = options.baseURL;
	if (options.headers) {
		Object.assign(defaultHeaders, options.headers);
	}
}

export async function get<TResponse, TParams extends QueryParams = QueryParams>(
	path: string,
	params?: TParams,
): Promise<TResponse> {
	const response = await axios.get<TResponse>(baseURL + path, {
		params,
		headers: defaultHeaders,
	});
	return response.data;
}

export async function post<TResponse, TBody = unknown>(
	path: string,
	body: TBody,
	options?: PostOptions,
): Promise<TResponse> {
	const response = await axios.post<TResponse>(baseURL + path, body, {
		headers: {
			...defaultHeaders,
			...(options?.headers ?? {}),
		},
	});
	return response.data;
}

export function buildQueryString(params: QueryParams): string {
	return Object.entries(params)
		.filter(([, v]) => v !== undefined && v !== null)
		.map(([k, v]) => `${encodeURIComponent(k)}=${encodeURIComponent(String(v))}`)
		.join('&');
}

function isRecord(value: unknown): value is Record<string, unknown> {
	return typeof value === 'object' && value !== null;
}

function hasItemsArray(
	value: unknown,
): value is { data: { items: unknown[] } } {
	if (!isRecord(value)) return false;
	const data = value.data;
	if (!isRecord(data)) return false;
	return Array.isArray(data.items);
}

function toParsedItem(item: unknown): ParsedItem {
	if (!isRecord(item)) {
		return { id: 'unknown', label: 'Unknown', meta: {} };
	}

	const idRaw = item.id;
	const id: string | number =
		typeof idRaw === 'string' || typeof idRaw === 'number' ? idRaw : 'unknown';

	const name = item.name;
	const title = item.title;
	const label =
		typeof name === 'string'
			? name
			: typeof title === 'string'
				? title
				: 'Unknown';

	const meta = isRecord(item.meta) ? item.meta : {};

	return { id, label, meta };
}

export function parseResponse(raw: unknown): ParsedItem[] {
	if (!hasItemsArray(raw)) {
		return [];
	}

	return raw.data.items.map(toParsedItem);
}

