   * @returns {EventBus} The EventBus instance.
   */
  EventBus.prototype.once = function (eventName, handler, context) {
    var self = this;

    function onceHandler() {
      self.off(eventName, onceHandler);
      handler.apply(context || self, arguments);
    }

