export function jaroWinkler(s1: string, s2: string): number {
	if (s1 === s2) return 1;

	const len1 = s1.length;
	const len2 = s2.length;

	if (len1 === 0 || len2 === 0) return 0;

	const matchDistance = Math.max(len1, len2) / 2 - 1;
	const s1Matches = new Array<boolean>(len1).fill(false);
	const s2Matches = new Array<boolean>(len2).fill(false);

	let matches = 0;

	for (let i = 0; i < len1; i++) {
		const start = Math.max(0, Math.floor(i - matchDistance));
		const end = Math.min(len2 - 1, Math.floor(i + matchDistance));

		for (let j = start; j <= end; j++) {
			if (s2Matches[j]) continue;
			if (s1[i] !== s2[j]) continue;

			s1Matches[i] = true;
			s2Matches[j] = true;
			matches++;
			break;
		}
	}

	if (matches === 0) return 0;

	let transpositions = 0;
	let k = 0;

	for (let i = 0; i < len1; i++) {
		if (!s1Matches[i]) continue;
		while (!s2Matches[k]) k++;
		if (s1[i] !== s2[k]) transpositions++;
		k++;
	}

	const m = matches;
	const jaro =
		(m / len1 + m / len2 + (m - transpositions / 2) / m) / 3;

	let prefix = 0;
	const maxPrefix = Math.min(4, len1, len2);
	for (let i = 0; i < maxPrefix; i++) {
		if (s1[i] === s2[i]) prefix++;
		else break;
	}

	const scalingFactor = 0.1;
	const winkler = jaro + prefix * scalingFactor * (1 - jaro);

	return Math.max(0, Math.min(1, winkler));
}

export type WrapOptions = {
	width?: number;
	lineBreak?: string;
	mode?: 'soft' | 'hard';
	hangingIndent?: string;
	collapseWhitespace?: boolean;
};

export function wordWrap(text: string, options: WrapOptions = {}): string {
	const width = Math.max(1, Math.floor(options.width ?? 80));
	const lineBreak = options.lineBreak ?? '\n';
	const mode = options.mode ?? 'soft';
	const hangingIndent = options.hangingIndent ?? '';
	const collapseWhitespace = options.collapseWhitespace ?? false;

	const paragraphs = text.split(/\r\n|\n|\r/);

	const wrappedParagraphs = paragraphs.map((paragraph) =>
		wrapParagraph(paragraph, {
			width,
			lineBreak,
			mode,
			hangingIndent,
			collapseWhitespace,
		}),
	);

	return wrappedParagraphs.join(lineBreak);
}

function wrapParagraph(
	paragraph: string,
	cfg: {
		width: number;
		lineBreak: string;
		mode: 'soft' | 'hard';
		hangingIndent: string;
		collapseWhitespace: boolean;
	},
): string {
	if (paragraph.length === 0) return '';

	const effective = cfg.collapseWhitespace
		? paragraph.trim().replace(/\s+/g, ' ')
		: paragraph;

	if (effective.length === 0) return '';

	if (cfg.mode === 'hard') {
		return wrapHard(effective, cfg.width, cfg.lineBreak, cfg.hangingIndent);
	}
	return wrapSoft(effective, cfg.width, cfg.lineBreak, cfg.hangingIndent);
}

function wrapSoft(text: string, width: number, lineBreak: string, hangingIndent: string): string {
	const words = text.trim().split(/\s+/).filter(Boolean);
	if (words.length === 0) return '';

	const lines: string[] = [];
	let current = '';
	let currentWidth = width;
	let firstLine = true;

	for (const word of words) {
		const w = word.length;
		if (current.length === 0) {
			if (firstLine) {
				if (w <= currentWidth) {
					current = word;
				} else {
					lines.push(word);
				}
			} else {
				const avail = Math.max(1, currentWidth - hangingIndent.length);
				if (w <= avail) {
					current = hangingIndent + word;
				} else {
					lines.push(hangingIndent + word);
				}
			}
		} else {
			if (current.length + 1 + w <= currentWidth) {
				current += ' ' + word;
			} else {
				lines.push(current);
				firstLine = false;
				currentWidth = width;
				const avail = Math.max(1, width - hangingIndent.length);
				if (w <= avail) {
					current = hangingIndent + word;
				} else {
					lines.push(hangingIndent + word);
					current = '';
				}
			}
		}
	}

	if (current.length > 0) lines.push(current);

	return lines.join(lineBreak);
}

function wrapHard(text: string, width: number, lineBreak: string, hangingIndent: string): string {
	const lines: string[] = [];
	let i = 0;
	let lineIndex = 0;

	while (i < text.length) {
		const prefix = lineIndex === 0 ? '' : hangingIndent;
		const contentWidth = Math.max(1, width - prefix.length);
		const chunk = text.slice(i, i + contentWidth);
		lines.push(prefix + chunk);
		i += chunk.length;
		lineIndex++;
	}

	return lines.join(lineBreak);
}

