async function* paginate(fetcher, startPage = 1) {
	let page = startPage;
	while (true) {
		const { items, hasMore } = await fetcher(page);
		for (const item of items) {
			yield item;
		}
		if (!hasMore) {
			break;
		}
		page++;
	}
}

