export function area(shape) {
	switch (shape.kind) {
		case 'circle':
			return Math.PI * shape.radius ** 2;
		case 'rectangle':
			return shape.width * shape.height;
		case 'triangle':
			return 0.5 * shape.base * shape.height;
		default:
			throw new Error(`Unhandled shape: ${JSON.stringify(shape)}`);
	}
}

const Direction = {
