};

export function opposite(d) {
	switch (d) {
		case Direction.Up:
			return Direction.Down;
		case Direction.Down:
			return Direction.Up;
		case Direction.Left:
			return Direction.Right;
		case Direction.Right:
			return Direction.Left;
	}
}

export function mergeDeep(target, source) {
	const result = {...target};
	for (const key in source) {
		const s = source[key];
		const t = target[key];
		if (s && typeof s === 'object' && !Array.isArray(s)) {
			result[key] = mergeDeep(t && typeof t === 'object' && !Array.isArray(t) ? t : {}, s);
		} else if (s !== undefined) {
			result[key] = s;
		}
	}
	return result;
}

