export function format(value) {
	if (Array.isArray(value)) {
		return value.map((n) => n.toFixed(2));
	}
	if (value instanceof Date) {
		return value.toISOString().slice(0, 10);
	}
	return value.toFixed(2);
}

function withCombinators(schema: { parse(input: unknown): unknown }) {
	return {
		...schema,
		optional() {
			return optional(this);
		},
		nullable() {
			return nullable(this);
		},
	};
}

function string() {
	return withCombinators({
		parse(input: unknown) {
			if (typeof input !== 'string') {
				throw new TypeError(`Expected string, got ${typeof input}`);
			}
			return input;
		},
	});
}

function optional(schema: { parse(input: unknown): unknown }) {
	return withCombinators({
		parse(input: unknown) {
			return input === undefined ? undefined : schema.parse(input);
		},
	});
}

function nullable(schema: { parse(input: unknown): unknown }) {
	return withCombinators({
		parse(input: unknown) {
			return input === null ? null : schema.parse(input);
		},
	});
}

export { string, optional, nullable };
